func TestReviewSession_CreatePersistsManifest(t *testing.T) {
	workDir := t.TempDir()
	store := NewReviewSessionStore(workDir)
	session := ReviewSession{
		ID:             "review-001",
		ArtifactID:     "art-123",
		ArtifactSHA:    "sha-abc",
		ArtifactGitRev: "gitrev-def",
		SystemRubric:   "rubric body",
